  // FK Keys\n  postId     Int\n  editedById Int\n\n  // Relations\n  post     Post @relation(fields: [postId], references: [id], onDelete: Cascade)\n  editedBy User @relation(\"PostEditor\", fields: [editedById], references: [id])\n\n  @@index([postId])\n  @@index([editedAt])\n}\n\nmodel Hashtag {\n  id        Int      @id @default(autoincrement())\n  name      String   @unique\n  createdAt DateTime @default(now())\n\n  // Relations\n  posts PostHashtag[]\n\n  @@index([name(sort: Asc)])\n}\n\nmodel PostHashtag {\n  id Int @id @default(autoincrement())\n\n  // FK Keys\n  postId    Int\n  hashtagId Int\n\n  // Relations\n  post    Post    @relation(fields: [postId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n  hashtag Hashtag @relation(fields: [hashtagId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n\n  @@unique([postId, hashtagId])\n}\n\nenum StoryPrivacy {\n  Public\n  FriendsOnly\n  CloseFriends\n}\n\nmodel Story {\n  id        Int          @id @default(autoincrement())\n  mediaUrl  String\n  caption   String?\n  privacy   StoryPrivacy @default(FriendsOnly)\n  expiresAt DateTime\n  createdAt DateTime     @default(now())\n\n  // FK Keys\n  userId Int\n\n  // Relations\n  user      User            @relation(fields: [userId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n  views     StoryView[]\n  reactions StoryReaction[]\n\n  @@index([userId])\n  @@index([expiresAt])\n  @@index([createdAt])\n}\n\nmodel StoryView {\n  id       Int      @id @default(autoincrement())\n  viewedAt DateTime @default(now())\n\n  // FK Keys\n  storyId Int\n  userId  Int\n\n  // Relations\n  story Story @relation(fields: [storyId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n  user  User  @relation(fields: [userId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n\n  @@unique([storyId, userId])\n  @@index([storyId])\n}\n\nmodel StoryReaction {\n  id        Int          @id @default(autoincrement())\n  reaction  ReactionType @default(Like)\n  createdAt DateTime     @default(now())\n\n  // FK Keys\n  storyId Int\n  userId  Int\n\n  // Relations\n  story Story @relation(fields: [storyId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n  user  User  @relation(fields: [userId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n\n  @@unique([storyId, userId])\n  @@index([storyId])\n}\n\nenum UserRole {\n  User\n  Admin\n  Moderator\n}\n\nenum FollowState {\n  pending\n  accepted\n  rejected\n}\n\nenum Gender {\n  Male\n  Female\n  Other\n  PreferNotToSay\n}\n\nenum ProfilePrivacy {\n  Public\n  FriendsOnly\n  Private\n}\n\nmodel User {\n  id               Int            @id @default(autoincrement())\n  userName         String         @unique\n  email            String         @unique\n  password         String?\n  role             UserRole       @default(User)\n  firstName        String?\n  lastName         String?\n  bio              String?\n  birthday         DateTime?\n  gender           Gender         @default(PreferNotToSay)\n  phone            String?\n  website          String?\n  location         String?\n  profilePrivacy   ProfilePrivacy @default(Public)\n  active           Boolean        @default(false)\n  canResetPassword Boolean        @default(false)\n  createdAt        DateTime       @default(now())\n  updatedAt        DateTime       @updatedAt\n\n  // Auth Relations\n  resetPasswordTokens ResetPasswordToken[]\n  activateTokens      ActivateToken[]\n  accounts            Account[]\n  sessions            Session[]\n\n  // Profile Relations\n  avatar     Avatar?\n  coverPhoto CoverPhoto?\n\n  // Social Graph Relations\n  followers UserFollow[] @relation(\"UserFollowing\")\n  following UserFollow[] @relation(\"UserFollowers\")\n  blockedBy UserBlock[]  @relation(\"BlockedUser\")\n  blocking  UserBlock[]  @relation(\"BlockingUser\")\n\n  // Post Relations\n  posts          Post[]\n  postLikes      PostLike[]\n  postSaves      PostSave[]\n  postShares     PostShare[]\n  postComments   PostComment[]\n  commentLikes   CommentLike[]\n  commentReplies CommentReply[]\n  replyLikes     ReplyLike[]\n  postsEdited    PostHistory[]  @relation(\"PostEditor\")\n\n  // Story Relations\n  stories        Story[]\n  storyViews     StoryView[]\n  storyReactions StoryReaction[]\n\n  // Messaging Relations\n  conversations    ConversationParticipant[]\n  messagesSent     Message[]                 @relation(\"MessageSender\")\n  messageReactions MessageReaction[]\n\n  // Group Relations\n  ownedGroups       Group[]            @relation(\"GroupOwner\")\n  groupMemberships  GroupMember[]\n  groupPosts        GroupPost[]\n  groupPostLikes    GroupPostLike[]\n  groupPostComments GroupPostComment[]\n\n  // Page Relations\n  ownedPages       Page[]            @relation(\"PageOwner\")\n  pageFollows      PageFollower[]\n  pagePosts        PagePost[]\n  pagePostLikes    PagePostLike[]\n  pagePostComments PagePostComment[]\n\n  // Event Relations\n  createdEvents         Event[]                @relation(\"EventCreator\")\n  eventAttendances      EventAttendee[]\n  eventPosts            EventPost[]\n  eventPostLikes        EventPostLike[]\n  eventPostComments     EventPostComment[]\n  eventPostCommentLikes EventPostCommentLike[]\n\n  // Memory Relations\n  memories Memory[]\n\n  // Comment Like Relations\n  pagePostCommentLikes  PagePostCommentLike[]\n  groupPostCommentLikes GroupPostCommentLike[]\n\n  // Notification Relations\n  notificationsReceived Notification[] @relation(\"NotificationReceiver\")\n  notificationsSent     Notification[] @relation(\"NotificationSender\")\n\n  // Moderation Relations\n  reportedContentCreated  ReportedContent[] @relation(\"ReportingUser\")\n  reportedContentReceived ReportedContent[] @relation(\"ReportedUser\")\n  moderationLogsCreated   ModerationLog[]   @relation(\"ModeratorUser\")\n  moderationLogsTargeted  ModerationLog[]   @relation(\"TargetUser\")\n\n  @@index([userName(sort: Asc)])\n  @@index([email])\n  @@index([createdAt])\n}\n\nmodel Avatar {\n  id        Int      @id @default(autoincrement())\n  photoSrc  String\n  createdAt DateTime @default(now())\n\n  // FK Keys\n  userId Int @unique\n\n  // Relations\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n}\n\nmodel CoverPhoto {\n  id        Int      @id @default(autoincrement())\n  photoSrc  String\n  createdAt DateTime @default(now())\n\n  // FK Keys\n  userId Int @unique\n\n  // Relations\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n}\n\nmodel UserFollow {\n  id        Int         @id @default(autoincrement())\n  state     FollowState @default(pending)\n  createdAt DateTime    @default(now())\n  updatedAt DateTime    @updatedAt\n\n  // FK Keys\n  followerId  Int\n  followingId Int\n\n  // Relations\n  follower  User @relation(\"UserFollowers\", fields: [followerId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n  following User @relation(\"UserFollowing\", fields: [followingId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n\n  @@unique([followerId, followingId])\n  @@index([state])\n  @@index([followerId])\n  @@index([followingId])\n}\n\nmodel UserBlock {\n  id        Int      @id @default(autoincrement())\n  createdAt DateTime @default(now())\n\n  // FK Keys\n  blockerId Int\n  blockedId Int\n\n  // Relations\n  blocker User @relation(\"BlockingUser\", fields: [blockerId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n  blocked User @relation(\"BlockedUser\", fields: [blockedId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n\n  @@unique([blockerId, blockedId])\n  @@index([blockerId])\n}\n",
